    23|struct VideoFeedService {
    24|    private static let apiBase = "https://api.ivxholding.com"
    25|
    26|    /// Ranked feed with deal enrichment (property title, price, ROI, deal link).
    27|    static func fetchFeed(limit: Int = 12) async throws -> [FeedVideo] {
    28|        guard let url = URL(string: "\(apiBase)/api/ivx/video-platform/feed?limit=\(limit)") else {
    29|            throw VideoFeedServiceError.badURL
    30|        }
    31|        var request = URLRequest(url: url)
    32|        request.httpMethod = "GET"
    33|        request.timeoutInterval = 15
    34|        request.setValue("application/json", forHTTPHeaderField: "Accept")
    35|
    36|        let (data, response) = try await URLSession.shared.data(for: request)
    37|        if let http = response as? HTTPURLResponse, !(200...299).contains(http.statusCode) {
    38|            throw VideoFeedServiceError.httpError(http.statusCode)
    39|        }
    40|        return try JSONDecoder().decode(FeedVideoResponse.self, from: data).videos
    41|    }
    42|
    43|    /// Project Reels rail — construction updates, drone footage, and progress
    44|    /// videos only. Served by the same canonical endpoint with ?type=reel so
    45|    /// reels never interrupt the investor deal flow of the main feed.
    46|    static func fetchProjectReels(limit: Int = 24) async throws -> [FeedVideo] {
    47|        guard let url = URL(string: "\(apiBase)/api/ivx/video-platform/feed?limit=\(limit)&type=reel") else {
    48|            throw VideoFeedServiceError.badURL
    49|        }
    50|        var request = URLRequest(url: url)
    51|        request.httpMethod = "GET"
    52|        request.timeoutInterval = 15
    53|        request.setValue("application/json", forHTTPHeaderField: "Accept")
    54|
    55|        let (data, response) = try await URLSession.shared.data(for: request)
    56|        if let http = response as? HTTPURLResponse, !(200...299).contains(http.statusCode) {
    57|            throw VideoFeedServiceError.httpError(http.statusCode)
    58|        }
    59|        return try JSONDecoder().decode(FeedVideoResponse.self, from: data).videos
    60|    }
    61|
    62|    /// Investor-first HOME feed — canonical block sequence for every platform:
    63|    /// Featured Deal 1–3 → 1 Featured Project Video → Deal 4–6 → repeat.
    64|    static func fetchHomeFeed(limit: Int = 60) async throws -> [HomeFeedBlock] {
    65|        guard let url = URL(string: "\(apiBase)/api/ivx/video-platform/home-feed?limit=\(limit)") else {
    66|            throw VideoFeedServiceError.badURL
    67|        }
    68|        var request = URLRequest(url: url)
    69|        request.httpMethod = "GET"
    70|        request.timeoutInterval = 15
    71|        request.setValue("application/json", forHTTPHeaderField: "Accept")
    72|
    73|        let (data, response) = try await URLSession.shared.data(for: request)
    74|        if let http = response as? HTTPURLResponse, !(200...299).contains(http.statusCode) {
    75|            throw VideoFeedServiceError.httpError(http.statusCode)
    76|        }
    77|        return try JSONDecoder().decode(HomeFeedResponse.self, from: data).blocks
    78|    }
