   120|async function loadEngagementCounts(sb: any, ids: string[]): Promise<Record<string, { likes: number; comments: number; shares: number; saves: number }>> {
   121|  const counts: Record<string, { likes: number; comments: number; shares: number; saves: number }> = {};
   122|  for (const id of ids) counts[id] = { likes: 0, comments: 0, shares: 0, saves: 0 };
   123|  if (ids.length === 0) return counts;
