    let createdAt: String?
    let videoType: String?
    let isFeatured: Bool?
    let isHidden: Bool?
    let status: String?
    let displayOrder: Double?

    enum CodingKeys: String, CodingKey {
        case id
        case projectId = "project_id"
        case videoUrl = "video_url"
        case hlsUrl = "hls_url"
        case posterUrl = "poster_url"
        case thumbnailUrl = "thumbnail_url"
